import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.aYYe0dfI.js";const h=JSON.parse('{"title":"Namespace clore::agent","description":"The clore::agent namespace encapsulates the core agent logic for a codebase exploration and documentation generation tool. It provides functions to build and register tool definitions (build_tool_definitions), dispatch tool calls (dispatch_tool_call), extract string arguments from tool-call JSON (extract_string_arg), and run the main agent loop both synchronously (run_agent) and asynchronously (run_agent_async). The namespace also defines error types (ToolError and AgentError) to communicate failures during tool execution or overall agent operation.","frontmatter":{"title":"Namespace clore::agent","description":"The clore::agent namespace encapsulates the core agent logic for a codebase exploration and documentation generation tool. It provides functions to build and register tool definitions (build_tool_definitions), dispatch tool calls (dispatch_tool_call), extract string arguments from tool-call JSON (extract_string_arg), and run the main agent loop both synchronously (run_agent) and asynchronously (run_agent_async). The namespace also defines error types (ToolError and AgentError) to communicate failures during tool execution or overall agent operation.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/namespaces/clore/agent/index.md","filePath":"en/clore/namespaces/clore/agent/index.md"}'),r={name:"clore/namespaces/clore/agent/index.md"};function l(c,e,s,i,d,u){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="namespace-clore-agent" tabindex="-1">Namespace <code>clore::agent</code> <a class="header-anchor" href="#namespace-clore-agent" aria-label="Permalink to &quot;Namespace `clore::agent`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>clore::agent</code> namespace encapsulates the core agent logic for a codebase exploration and documentation generation tool. It provides functions to build and register tool definitions (<code>build_tool_definitions</code>), dispatch tool calls (<code>dispatch_tool_call</code>), extract string arguments from tool-call JSON (<code>extract_string_arg</code>), and run the main agent loop both synchronously (<code>run_agent</code>) and asynchronously (<code>run_agent_async</code>). The namespace also defines error types (<code>ToolError</code> and <code>AgentError</code>) to communicate failures during tool execution or overall agent operation.</p><p>Architecturally, <code>clore::agent</code> acts as the orchestrator of an LLM‑driven agent that issues tool calls to analyze a codebase. It manages an internal tool registry, a result cache for tool invocations, and configuration variables such as <code>output_root</code> (for generated guides), <code>model</code> (the LLM backend), and <code>config</code> (operational parameters). The agent loop iterates over tool call results, producing structured documents under the output root directory. This namespace serves as the primary interface for initiating and controlling the agent’s workflow within the larger <code>clore</code> system.</p><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-agent-agenterror" tabindex="-1"><code>clore::agent::AgentError</code> <a class="header-anchor" href="#clore-agent-agenterror" aria-label="Permalink to &quot;`clore::agent::AgentError`&quot;">​</a></h3><p>Declaration: <code>agent/agent.cppm:21</code></p><p>Definition: <code>agent/agent.cppm:21</code></p><p>Implementation: <a href="./../../../modules/agent/"><code>Module agent</code></a></p><p>Insufficient evidence to summarize; provide more EVIDENCE.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>message should be a valid, non-empty string when describing an error</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li>message</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used as a return type or thrown as an exception to indicate agent-related errors</li></ul><h3 id="clore-agent-toolerror" tabindex="-1"><code>clore::agent::ToolError</code> <a class="header-anchor" href="#clore-agent-toolerror" aria-label="Permalink to &quot;`clore::agent::ToolError`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:16</code></p><p>Definition: <code>agent/tools.cppm:16</code></p><p>Implementation: <a href="./../../../modules/agent/tools"><code>Module agent:tools</code></a></p><p>The <code>clore::agent::ToolError</code> struct represents an error type specifically for tool-related operations within the agent framework. It is used to capture and communicate failures that occur during the execution or handling of tools, and it complements the more general <code>clore::agent::AgentError</code> struct.</p><h4 id="invariants-1" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-1" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>No explicit invariants beyond the presence of a message string.</li></ul><h4 id="key-members-1" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-1" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>std::string message</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Returned or thrown by tool-related functions to indicate failure with a descriptive message.</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-agent-build-tool-definitions" tabindex="-1"><code>clore::agent::build_tool_definitions</code> <a class="header-anchor" href="#clore-agent-build-tool-definitions" aria-label="Permalink to &quot;`clore::agent::build_tool_definitions`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:23</code></p><p>Definition: <code>agent/tools.cppm:887</code></p><p>Implementation: <a href="./../../../modules/agent/tools"><code>Module agent:tools</code></a></p><p>The function <code>clore::agent::build_tool_definitions</code> constructs and registers the complete set of tool definitions used by the agent. It takes no arguments and returns an <code>int</code> indicating success (zero) or failure (a non‑zero error code). Callers must invoke this function during agent initialization to populate the internal tool registry; after a successful call, the agent can dispatch tool calls via <code>clore::agent::dispatch_tool_call</code> and execute tool‑based workflows with <code>clore::agent::run_agent</code> or <code>clore::agent::run_agent_async</code>.</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Obtain tool definitions for sending to a language model</li><li>Called by agent initialization or tool call dispatch logic</li></ul><h3 id="clore-agent-dispatch-tool-call" tabindex="-1"><code>clore::agent::dispatch_tool_call</code> <a class="header-anchor" href="#clore-agent-dispatch-tool-call" aria-label="Permalink to &quot;`clore::agent::dispatch_tool_call`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:26</code></p><p>Definition: <code>agent/tools.cppm:902</code></p><p>Implementation: <a href="./../../../modules/agent/tools"><code>Module agent:tools</code></a></p><p>The function <code>clore::agent::dispatch_tool_call</code> is the caller-facing dispatcher for executing a tool identified by name. It accepts the tool name as a <code>std::string_view</code>, the tool’s arguments as a <code>const json::Value &amp;</code>, an integer (likely a request or sequence identifier), and two additional <code>std::string_view</code> parameters (typically representing a session or invocation context). It returns a <code>std::expected&lt;std::string, ToolError&gt;</code>, either yielding the tool’s output as a string or reporting a <code>ToolError</code> on failure.</p><p>The caller is responsible for ensuring that the tool name corresponds to a valid, built tool definition and that the arguments are well-formed JSON. The function may internally interact with a per-session result cache (<code>tool_result_cache</code>) to avoid redundant execution. The contract expects the caller to handle both the success value and the error case appropriately.</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to handle tool calls in agent execution loops</li><li>used by functions such as <code>run_agent_async</code> and <code>run_agent</code> to process tool dispatch requests</li></ul><h3 id="clore-agent-extract-string-arg" tabindex="-1"><code>clore::agent::extract_string_arg</code> <a class="header-anchor" href="#clore-agent-extract-string-arg" aria-label="Permalink to &quot;`clore::agent::extract_string_arg`&quot;">​</a></h3><p>Declaration: <code>agent/tools.cppm:20</code></p><p>Definition: <code>agent/tools.cppm:865</code></p><p>Implementation: <a href="./../../../modules/agent/tools"><code>Module agent:tools</code></a></p><p>The function <code>clore::agent::extract_string_arg</code> retrieves a string-valued argument from a JSON object based on the argument name provided as <code>std::string_view</code>. It serves as a validation and extraction helper for tool-call handling, ensuring the requested argument exists and is of the expected type. On success it returns the extracted string; on failure it returns a <code>ToolError</code> indicating the specific error (e.g., missing key or type mismatch). The caller must supply a valid <code>json::Value</code> (typically the arguments object of a tool call) and the name of the argument to extract.</p><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used by <code>dispatch_tool_call</code> to extract string arguments from tool call argument objects</li></ul><h3 id="clore-agent-run-agent" tabindex="-1"><code>clore::agent::run_agent</code> <a class="header-anchor" href="#clore-agent-run-agent" aria-label="Permalink to &quot;`clore::agent::run_agent`&quot;">​</a></h3><p>Declaration: <code>agent/agent.cppm:27</code></p><p>Definition: <code>agent/agent.cppm:524</code></p><p>Implementation: <a href="./../../../modules/agent/"><code>Module agent</code></a></p><p>The <code>clore::agent::run_agent</code> function executes the core agent loop. It explores the codebase by issuing tool calls and, on success, produces guide documents under the configured output root directory. Callers supply four arguments — two <code>const int &amp;</code> values, a <code>std::string_view</code>, and a <code>std::string</code> — which collectively define the agent’s operational parameters (e.g., concurrency limits, output path). The function returns a <code>std::expected&lt;std::size_t, AgentError&gt;</code>: on success it yields a count (likely the number of guides generated), and on failure it provides a descriptive <code>AgentError</code>. The function is synchronous and does not throw exceptions; callers must handle the expected result to determine success or failure.</p><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>synchronous entry point for running the agent</li><li>callers use it to execute the agent loop and obtain a result</li><li>typically called with a configuration, project model, LLM model name, and output directory</li></ul><h3 id="clore-agent-run-agent-async" tabindex="-1"><code>clore::agent::run_agent_async</code> <a class="header-anchor" href="#clore-agent-run-agent-async" aria-label="Permalink to &quot;`clore::agent::run_agent_async`&quot;">​</a></h3><p>Declaration: <code>agent/agent.cppm:34</code></p><p>Definition: <code>agent/agent.cppm:507</code></p><p>Implementation: <a href="./../../../modules/agent/"><code>Module agent</code></a></p><p>The function <code>clore::agent::run_agent_async</code> initiates an asynchronous agent loop that runs on a caller-provided <code>kota::event_loop</code>. It accepts two <code>const int &amp;</code> parameters, two <code>std::string</code> parameters, and a <code>kota::event_loop &amp;</code>. The function returns a task representing the loop; callers must schedule this task on the supplied event loop and run it. The caller is responsible for ensuring the event loop remains active while the task executes.</p><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>callers must schedule the returned task on the event loop and run it</li><li>used to start an asynchronous agent loop with cache loading</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore</a></li></ul>',66)])])}const p=a(r,[["render",l]]);export{h as __pageData,p as default};
